import{_ as t,c as o,o as i,a1 as a}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Version History | opencode-agent-skills","description":"Learn about the version evolution history of the OpenCode Agent Skills plugin. This tutorial covers all major feature updates, bug fixes, architecture improvements, and breaking changes from v0.1.0 to v0.6.4.","frontmatter":{"title":"Version History | opencode-agent-skills","sidebarTitle":"Changelog","subtitle":"Version History | opencode-agent-skills","description":"Learn about the version evolution history of the OpenCode Agent Skills plugin. This tutorial covers all major feature updates, bug fixes, architecture improvements, and breaking changes from v0.1.0 to v0.6.4.","tags":["Version Updates","changelog","Release History"],"order":1},"headers":[],"relativePath":"joshuadavidthomas/opencode-agent-skills/changelog/index.md","filePath":"joshuadavidthomas/opencode-agent-skills/changelog/index.md"}'),d={name:"joshuadavidthomas/opencode-agent-skills/changelog/index.md"};function r(n,e,l,s,c,u){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="version-history" tabindex="-1">Version History <a class="header-anchor" href="#version-history" aria-label="Permalink to &quot;Version History&quot;">​</a></h1><p>This document records all version updates of the OpenCode Agent Skills plugin. Through the version history, you can understand the evolution path of features, fixed issues, and architecture improvements.</p><div class="tip custom-block"><p class="custom-block-title">Current Version</p><p>The latest stable version is <strong>v0.6.4</strong> (2026-01-20)</p></div><h2 id="version-timeline" tabindex="-1">Version Timeline <a class="header-anchor" href="#version-timeline" aria-label="Permalink to &quot;Version Timeline&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Release Date</th><th>Type</th><th>Main Content</th></tr></thead><tbody><tr><td>0.6.4</td><td>2026-01-20</td><td>Fix</td><td>YAML parsing, Claude v2 support</td></tr><tr><td>0.6.3</td><td>2025-12-16</td><td>Improvement</td><td>Optimize skill recommendation prompts</td></tr><tr><td>0.6.2</td><td>2025-12-15</td><td>Fix</td><td>Separate skill name from directory name</td></tr><tr><td>0.6.1</td><td>2025-12-13</td><td>Improvement</td><td>Avoid recommending already loaded skills</td></tr><tr><td>0.6.0</td><td>2025-12-12</td><td>New Feature</td><td>Semantic matching, embedding precomputation</td></tr><tr><td>0.5.0</td><td>2025-12-11</td><td>Improvement</td><td>Fuzzy matching suggestions, refactoring</td></tr><tr><td>0.4.1</td><td>2025-12-08</td><td>Improvement</td><td>Simplify installation method</td></tr><tr><td>0.4.0</td><td>2025-12-05</td><td>Improvement</td><td>Recursive script search</td></tr><tr><td>0.3.3</td><td>2025-12-02</td><td>Fix</td><td>Symlink handling</td></tr><tr><td>0.3.2</td><td>2025-11-30</td><td>Fix</td><td>Preserve agent mode</td></tr><tr><td>0.3.1</td><td>2025-11-28</td><td>Fix</td><td>Model switching issue</td></tr><tr><td>0.3.0</td><td>2025-11-27</td><td>New Feature</td><td>File listing functionality</td></tr><tr><td>0.2.0</td><td>2025-11-26</td><td>New Feature</td><td>Superpowers mode</td></tr><tr><td>0.1.0</td><td>2025-11-26</td><td>Initial</td><td>4 tools, multi-location discovery</td></tr></tbody></table><h2 id="detailed-change-log" tabindex="-1">Detailed Change Log <a class="header-anchor" href="#detailed-change-log" aria-label="Permalink to &quot;Detailed Change Log&quot;">​</a></h2><h3 id="v0-6-4-2026-01-20" tabindex="-1">v0.6.4 (2026-01-20) <a class="header-anchor" href="#v0-6-4-2026-01-20" aria-label="Permalink to &quot;v0.6.4 (2026-01-20)&quot;">​</a></h3><p><strong>Fixes</strong>:</p><ul><li>Fixed YAML frontmatter parsing for skill multi-line descriptions (supporting <code>|</code> and <code>&gt;</code> block scalar syntax) by replacing custom parser with <code>yaml</code> library</li><li>Added support for Claude plugin v2 format, <code>installed_plugins.json</code> now uses plugin installation array instead of single object</li></ul><p><strong>Improvements</strong>:</p><ul><li>Claude Code plugin cache discovery now supports new nested directory structure (<code>cache/&lt;marketplace&gt;/&lt;plugin&gt;/&lt;version&gt;/skills/</code>)</li></ul><h3 id="v0-6-3-2025-12-16" tabindex="-1">v0.6.3 (2025-12-16) <a class="header-anchor" href="#v0-6-3-2025-12-16" aria-label="Permalink to &quot;v0.6.3 (2025-12-16)&quot;">​</a></h3><p><strong>Improvements</strong>:</p><ul><li>Optimized skill evaluation prompts to prevent models from sending &quot;no skill needed&quot; messages to users (users don&#39;t see hidden evaluation prompts)</li></ul><h3 id="v0-6-2-2025-12-15" tabindex="-1">v0.6.2 (2025-12-15) <a class="header-anchor" href="#v0-6-2-2025-12-15" aria-label="Permalink to &quot;v0.6.2 (2025-12-15)&quot;">​</a></h3><p><strong>Fixes</strong>:</p><ul><li>Skill validation now allows directory names to differ from the <code>name</code> in SKILL.md frontmatter. The <code>name</code> in frontmatter is the canonical identifier, while directory names are only for organization. This aligns with the Anthropic Agent Skills specification.</li></ul><h3 id="v0-6-1-2025-12-13" tabindex="-1">v0.6.1 (2025-12-13) <a class="header-anchor" href="#v0-6-1-2025-12-13" aria-label="Permalink to &quot;v0.6.1 (2025-12-13)&quot;">​</a></h3><p><strong>Improvements</strong>:</p><ul><li>Dynamic skill recommendations now track loaded skills per session to avoid recommending already loaded skills, reducing redundant prompts and context usage</li></ul><h3 id="v0-6-0-2025-12-12" tabindex="-1">v0.6.0 (2025-12-12) <a class="header-anchor" href="#v0-6-0-2025-12-12" aria-label="Permalink to &quot;v0.6.0 (2025-12-12)&quot;">​</a></h3><p><strong>Additions</strong>:</p><ul><li><strong>Semantic Skill Matching</strong>: After initial skill list injection, subsequent messages use local embeddings to match with skill descriptions</li><li>Added <code>@huggingface/transformers</code> dependency for local embedding generation (quantized all-MiniLM-L6-v2)</li><li>When messages match available skills, inject 3-step evaluation prompt (EVALUATE → DECIDE → ACTIVATE) to encourage skill loading (inspired by <a href="https://github.com/spences10" target="_blank" rel="noreferrer">@spences10</a>&#39;s <a href="https://scottspence.com/posts/how-to-make-claude-code-skills-activate-reliably" target="_blank" rel="noreferrer">blog post</a>)</li><li>Cache embeddings on disk for low-latency matching (~/.cache/opencode-agent-skills/)</li><li>Clean up sessions on <code>session.deleted</code> event</li></ul><h3 id="v0-5-0-2025-12-11" tabindex="-1">v0.5.0 (2025-12-11) <a class="header-anchor" href="#v0-5-0-2025-12-11" aria-label="Permalink to &quot;v0.5.0 (2025-12-11)&quot;">​</a></h3><p><strong>Additions</strong>:</p><ul><li>Added &quot;Did you mean...&quot; fuzzy matching suggestions in all tools (<code>use_skill</code>, <code>read_skill_file</code>, <code>run_skill_script</code>, <code>get_available_skills</code>)</li></ul><p><strong>Improvements</strong>:</p><ul><li><strong>Breaking Change</strong>: Renamed <code>find_skills</code> tool to <code>get_available_skills</code> for clearer intent</li><li><strong>Internal</strong>: Reorganized codebase into separate modules (<code>claude.ts</code>, <code>skills.ts</code>, <code>tools.ts</code>, <code>utils.ts</code>, <code>superpowers.ts</code>) for improved maintainability</li><li><strong>Internal</strong>: Improved code quality by removing AI-generated comments and unnecessary code</li></ul><h3 id="v0-4-1-2025-12-08" tabindex="-1">v0.4.1 (2025-12-08) <a class="header-anchor" href="#v0-4-1-2025-12-08" aria-label="Permalink to &quot;v0.4.1 (2025-12-08)&quot;">​</a></h3><p><strong>Improvements</strong>:</p><ul><li>Installation method now uses npm package via OpenCode config instead of git clone + symlink</li></ul><p><strong>Removals</strong>:</p><ul><li>Removed <code>INSTALL.md</code> (no longer needed after simplification)</li></ul><h3 id="v0-4-0-2025-12-05" tabindex="-1">v0.4.0 (2025-12-05) <a class="header-anchor" href="#v0-4-0-2025-12-05" aria-label="Permalink to &quot;v0.4.0 (2025-12-05)&quot;">​</a></h3><p><strong>Improvements</strong>:</p><ul><li>Script discovery now recursively searches the entire skill directory (max depth 10) instead of only root directory and <code>scripts/</code> subdirectory</li><li>Scripts are now identified by relative paths (e.g., <code>tools/build.sh</code>) instead of base names</li><li>Renamed <code>skill_name</code> parameter to <code>skill</code> in <code>read_skill_file</code>, <code>run_skill_script</code>, and <code>use_skill</code> tools</li><li>Renamed <code>script_name</code> parameter to <code>script</code> in <code>run_skill_script</code> tool</li></ul><h3 id="v0-3-3-2025-12-02" tabindex="-1">v0.3.3 (2025-12-02) <a class="header-anchor" href="#v0-3-3-2025-12-02" aria-label="Permalink to &quot;v0.3.3 (2025-12-02)&quot;">​</a></h3><p><strong>Fixes</strong>:</p><ul><li>Fixed file and directory detection by using <code>fs.stat</code> to correctly handle symbolic links</li></ul><h3 id="v0-3-2-2025-11-30" tabindex="-1">v0.3.2 (2025-11-30) <a class="header-anchor" href="#v0-3-2-2025-11-30" aria-label="Permalink to &quot;v0.3.2 (2025-11-30)&quot;">​</a></h3><p><strong>Fixes</strong>:</p><ul><li>Preserved agent mode when injecting synthetic messages at session start</li></ul><h3 id="v0-3-1-2025-11-28" tabindex="-1">v0.3.1 (2025-11-28) <a class="header-anchor" href="#v0-3-1-2025-11-28" aria-label="Permalink to &quot;v0.3.1 (2025-11-28)&quot;">​</a></h3><p><strong>Fixes</strong>:</p><ul><li>Fixed unintended model switching when using skill tools by explicitly passing current model in <code>noReply</code> operation (temporary workaround for opencode issue #4475)</li></ul><h3 id="v0-3-0-2025-11-27" tabindex="-1">v0.3.0 (2025-11-27) <a class="header-anchor" href="#v0-3-0-2025-11-27" aria-label="Permalink to &quot;v0.3.0 (2025-11-27)&quot;">​</a></h3><p><strong>Additions</strong>:</p><ul><li>Added file list in <code>use_skill</code> output</li></ul><h3 id="v0-2-0-2025-11-26" tabindex="-1">v0.2.0 (2025-11-26) <a class="header-anchor" href="#v0-2-0-2025-11-26" aria-label="Permalink to &quot;v0.2.0 (2025-11-26)&quot;">​</a></h3><p><strong>Additions</strong>:</p><ul><li>Added Superpowers mode support</li><li>Added release proof</li></ul><h3 id="v0-1-0-2025-11-26" tabindex="-1">v0.1.0 (2025-11-26) <a class="header-anchor" href="#v0-1-0-2025-11-26" aria-label="Permalink to &quot;v0.1.0 (2025-11-26)&quot;">​</a></h3><p><strong>Additions</strong>:</p><ul><li>Added <code>use_skill</code> tool to load skill content into context</li><li>Added <code>read_skill_file</code> tool to read supporting files in skill directory</li><li>Added <code>run_skill_script</code> tool to execute scripts from skill directory</li><li>Added <code>find_skills</code> tool to search and list available skills</li><li>Added multi-location skill discovery (project-level, user-level, and Claude-compatible locations)</li><li>Added frontmatter validation compliant with Anthropic Agent Skills Spec v1.0</li><li>Added automatic skill list injection at session start and after context compression</li></ul><p><strong>New Contributors</strong>:</p><ul><li>Josh Thomas <a href="mailto:josh@joshthomas.dev" target="_blank" rel="noreferrer">josh@joshthomas.dev</a> (Maintainer)</li></ul><h2 id="feature-evolution-overview" tabindex="-1">Feature Evolution Overview <a class="header-anchor" href="#feature-evolution-overview" aria-label="Permalink to &quot;Feature Evolution Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Introduced Version</th><th>Evolution Path</th></tr></thead><tbody><tr><td>4 Basic Tools</td><td>v0.1.0</td><td>v0.5.0 added fuzzy matching</td></tr><tr><td>Multi-location Skill Discovery</td><td>v0.1.0</td><td>v0.4.1 simplified installation, v0.6.4 added Claude v2 support</td></tr><tr><td>Auto Context Injection</td><td>v0.1.0</td><td>v0.3.0 added file list, v0.6.1 avoided duplicate recommendations</td></tr><tr><td>Superpowers Mode</td><td>v0.2.0</td><td>Continuously stable</td></tr><tr><td>Recursive Script Search</td><td>v0.4.0</td><td>v0.3.3 fixed symlinks</td></tr><tr><td>Semantic Matching Recommendation</td><td>v0.6.0</td><td>v0.6.1 avoided duplicates, v0.6.3 optimized prompts</td></tr><tr><td>Fuzzy Matching Suggestions</td><td>v0.5.0</td><td>Continuously stable</td></tr></tbody></table><h2 id="breaking-changes" tabindex="-1">Breaking Changes <a class="header-anchor" href="#breaking-changes" aria-label="Permalink to &quot;Breaking Changes&quot;">​</a></h2><h3 id="v0-6-0-semantic-matching-feature" tabindex="-1">v0.6.0: Semantic Matching Feature <a class="header-anchor" href="#v0-6-0-semantic-matching-feature" aria-label="Permalink to &quot;v0.6.0: Semantic Matching Feature&quot;">​</a></h3><p>Introduced local embedding-based semantic matching capability, allowing AI to automatically recommend relevant skills based on user message content without users needing to memorize skill names.</p><ul><li><strong>Technical Details</strong>: Using HuggingFace&#39;s <code>all-MiniLM-L6-v2</code> model (q8 quantized)</li><li><strong>Caching Mechanism</strong>: Embedding results cached to <code>~/.cache/opencode-agent-skills/</code>, improving subsequent matching speed</li><li><strong>Matching Process</strong>: User message → embedding → calculate cosine similarity with skill descriptions → Top 5 recommendations (threshold 0.35)</li></ul><h3 id="v0-5-0-refactoring-and-tool-renaming" tabindex="-1">v0.5.0: Refactoring and Tool Renaming <a class="header-anchor" href="#v0-5-0-refactoring-and-tool-renaming" aria-label="Permalink to &quot;v0.5.0: Refactoring and Tool Renaming&quot;">​</a></h3><p>Code architecture refactored to modular design with clearer tool naming:</p><ul><li><code>find_skills</code> → <code>get_available_skills</code></li><li><code>skill_name</code> → <code>skill</code></li><li><code>script_name</code> → <code>script</code></li></ul><h3 id="v0-4-0-script-discovery-mechanism-upgrade" tabindex="-1">v0.4.0: Script Discovery Mechanism Upgrade <a class="header-anchor" href="#v0-4-0-script-discovery-mechanism-upgrade" aria-label="Permalink to &quot;v0.4.0: Script Discovery Mechanism Upgrade&quot;">​</a></h3><p>Script discovery upgraded from &quot;root directory + scripts/ only&quot; to &quot;recursive search of entire skill directory&quot; (max depth 10), supporting more flexible script organization.</p><h3 id="v0-2-0-superpowers-integration" tabindex="-1">v0.2.0: Superpowers Integration <a class="header-anchor" href="#v0-2-0-superpowers-integration" aria-label="Permalink to &quot;v0.2.0: Superpowers Integration&quot;">​</a></h3><p>Added support for Superpowers workflow mode, requiring installation of <code>using-superpowers</code> skill and setting environment variable <code>OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE=true</code>.</p><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line</th></tr></thead><tbody><tr><td>Current Version</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/package.json#L3-L3" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>3</td></tr><tr><td>Version History</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/CHANGELOG.md#L19-L152" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a></td><td>19-152</td></tr></tbody></table><p><strong>Key Version Information</strong>:</p><ul><li><code>v0.6.4</code>: Current version (2026-01-20)</li><li><code>v0.6.0</code>: Semantic matching introduced (2025-12-12)</li><li><code>v0.5.0</code>: Refactoring version (2025-12-11)</li><li><code>v0.1.0</code>: Initial version (2025-11-26)</li></ul></details>',72)])])}const m=t(d,[["render",r]]);export{p as __pageData,m as default};
